INSERT INTO users (username, email, password, full_name, phone, role, theater_id, enabled, email_verified, tier, storage_state)
SELECT N'cinex.hn',  N'admin.hn@cinex.vn',  N'$2a$10$3KqUMOI7eM7WICDg0aH8I.AnzZpotYqJ.dnHEr3K6Xk8O4nGWRMBe', N'Quản lý CineX Hà Nội',     N'0901000001', N'ADMIN', id, 1, 1, N'STANDARD', N'ACTIVE' FROM theaters WHERE code = N'CNX-HN';

